operations.query:
query {
    promotionCoupons(storeId: "B2B-store" first: 1) {
      items { id couponCode }
    }
  }

mutation {
    addCoupon(command: { storeId: "B2B-store" userId: "user-acme-store-maintainer-1" couponCode: "E2E-COUPON" }) {
      id
      coupons { code isAppliedSuccessfully }
      discountTotal { amount }
      total { amount }
      subTotal { amount }
    }
  }
